"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { Icon } from "@/components/icon";
import { Card, CardContent } from "@/components/ui/card";
import { toast } from "sonner";
// import { Button } from "@/components/ui/button";
// import { Input } from "@/components/ui/input";
// import { Search } from "lucide-react";

type BankAccount = {
  id: number;
  bank_name: string;
  account_number: string;
  account_holder_name: string;
};

const BanksForm = () => {
  const [accounts, setAccounts] = useState<BankAccount[]>([]);
  const [loading, setLoading] = useState(true);
  const [deletingId, setDeletingId] = useState<number | null>(null);

  useEffect(() => {
    let cancelled = false;
    (async () => {
      try {
        const res = await fetch("/api/account/banks", { credentials: "include", cache: "no-store" });
        const json = await res.json().catch(() => ({}));
        if (!cancelled && json?.success && Array.isArray(json?.data)) {
          setAccounts(json.data);
        }
      } finally {
        if (!cancelled) setLoading(false);
      }
    })();
    return () => { cancelled = true; };
  }, []);

  return (
      <>
          <Card>
            <CardContent>
              <div>
                <h1 className="text-12  md:text-14 lg:text-16 font-bold">
                  Kamu Bisa Simpan Rekening Bank Untuk Metode Pembayaran
                </h1>
                <p className="text-10  md:text-12  lg:text-14 text-sm text-muted-foreground mt-1">
                  Kelola data rekening mitra yang digunakan untuk proses pencairan dana dan transaksi lainnya.
                </p>
              </div>
            </CardContent>
            <CardContent>
              <Link href={"/account/bank/create"} prefetch>
                <div className="text-10 md:text-12 lg:text-14 px-4 w-full font-bold h-16 flex justify-center items-center bg-white rounded-xl border-[0.5px]">
                  <div className="flex items-center justify-between w-full">
                    <div className="p-2 bg-khaffah-primary/10 rounded-lg">
                      <Icon name="Card" className="fill-khaffah-primary" />
                    </div>
                    <p>Tambah Rekening Baru</p>
                    <button
                      type="button"
                      className="p-2 bg-khaffah-primary/10 rounded-lg"
                    >
                      <Icon name="Plus" className="fill-khaffah-primary" />
                    </button>
                  </div>
                </div>
              </Link>
            </CardContent>
            
          </Card>
          <hr className="py-2" />
          <Card className="md:px-4 lg:px-6 rounded-none md:rounded-2xl">
                <CardContent>
                    {loading ? (
                        <div className="flex flex-col items-center justify-center py-8 text-khaffah-neutral-mid">Memuat...</div>
                    ) : accounts.length > 0 ? (
                        <div className="flex flex-col gap-4">
                            {accounts.map((acc) => (
                              <div
                                key={acc.id}
                                className="flex items-center justify-between bg-white shadow-md rounded-xl p-5 border border-gray-100"
                              >
                                <div className="flex gap-4 items-start">
                                  <div className="p-2 bg-khaffah-primary/10 rounded-lg">
                                    <Icon name="Card" className="fill-khaffah-primary w-10 h-10" />
                                  </div>
                                  <div className="flex flex-col">
                                    <p className="text-sm text-gray-600 font-medium">{acc.bank_name}</p>
                                    <p className="text-lg font-bold tracking-wide">{acc.account_number}</p>
                                    <p className="text-xs text-gray-500 mt-1">A.N {acc.account_holder_name}</p>
                                  </div>
                                </div>
                                <button
                                  type="button"
                                  disabled={deletingId === acc.id}
                                  onClick={async () => {
                                    if (!confirm("Yakin ingin menghapus rekening ini?")) return;
                                    try {
                                      setDeletingId(acc.id);
                                      const res = await fetch(`/api/account/banks/${acc.id}`, {
                                        method: "DELETE",
                                        credentials: "include",
                                      });
                                      const data = await res.json().catch(() => ({}));
                                      if (!res.ok) {
                                        toast.error(data?.message ?? "Gagal menghapus rekening.");
                                        return;
                                      }
                                      setAccounts((prev) => prev.filter((a) => a.id !== acc.id));
                                      toast.success("Rekening berhasil dihapus.");
                                    } catch {
                                      toast.error("Terjadi kesalahan. Silakan coba lagi.");
                                    } finally {
                                      setDeletingId(null);
                                    }
                                  }}
                                  className="text-10 md:text-12 lg:text-14 px-3 py-2 rounded-lg border border-red-200 text-red-600 font-semibold hover:bg-red-50 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                                >
                                  {deletingId === acc.id ? "Menghapus..." : "Hapus"}
                                </button>
                              </div>
                            ))}
                        </div>
                    ) : (
                    <div className="flex flex-col items-center justify-center border rounded-xl pb-4">
                        <svg
                            width="241"
                            height="240"
                            viewBox="0 0 241 240"
                            fill="none"
                            xmlns="http://www.w3.org/2000/svg"
                            xmlnsXlink="http://www.w3.org/1999/xlink"
                        >
                            <rect
                                x="0.5"
                                width="240"
                                height="240"
                                rx="16"
                                fill="url(#pattern0_4219_32548)"
                            />
                            <defs>
                                <pattern
                                    id="pattern0_4219_32548"
                                    patternContentUnits="objectBoundingBox"
                                    width="1"
                                    height="1"
                                >
                                    <use
                                        xlinkHref="#image0_4219_32548"
                                        transform="scale(0.001)"
                                    />
                                </pattern>
                                <image
                                    id="image0_4219_32548"
                                    width="1000"
                                    height="1000"
                                    preserveAspectRatio="none"
                                    xlinkHref="data:image/png;base64,"
                                />
                            </defs>
                        </svg>
                        <p className="text-12 md:text-14 lg:text-16 font-bold text-khaffah-neutral-dark">
                            Kamu belum mendaftarkan rekening kamu disini
                        </p>
                        <p className="text-10 md:text-12 lg:text-14 text-khaffah-neutral-mid">
                            Belum ada data rekening yang terdaftar. Klik tombol Tambah Rekening untuk mulai mengisi informasi rekening kamu..
                        </p>
                    </div>
                    )}
                </CardContent>
            </Card>
      </>
  );
};

export default BanksForm;